// src/components/TelaEsterilizacao.jsx
import React, { useState, useEffect, useRef, useCallback } from 'react'
import axios from 'axios'
import { toast } from 'react-toastify'
import { Calendar } from 'lucide-react'
import DatePicker from 'react-datepicker'
import { subDays, formatISO } from 'date-fns'
import 'react-datepicker/dist/react-datepicker.css'

export default function TelaEsterilizacao() {
  const [codigo, setCodigo] = useState('')
  const [allCaixas, setAllCaixas] = useState([])
  const [caixas, setCaixas] = useState([])
  const [alunoPin, setAlunoPin] = useState('')
  const [alunoNome, setAlunoNome] = useState('')        // ← guarda nome do aluno
  const [pinValidated, setPinValidated] = useState(false)
  const [historico, setHistorico] = useState([])
  const [searchTerm, setSearchTerm] = useState('')
  const [filterDate, setFilterDate] = useState('')
  const datePickerRef = useRef(null)

  // carrega todas as caixas para autocomplete
  useEffect(() => {
    axios.get('/api/caixas')
      .then(res => setAllCaixas(res.data))
      .catch(() => setAllCaixas([]))
  }, [])

  // busca histórico do aluno nos últimos 30 dias, após validação
  // agora retorna a promise para podermos extrair o nome
  const fetchHistory = useCallback(() => {
    if (!pinValidated) return Promise.resolve({ data: [] })
    const hoje = new Date()
    const from = subDays(hoje, 30)
    return axios.get('/api/movimentacoes', {
      params: {
        aluno_pin: alunoPin,
        from: formatISO(from, { representation: 'date' }),
        to:   formatISO(hoje, { representation: 'date' })
      }
    })
    .then(res => {
      setHistorico(res.data)
      // se houver ao menos uma movimentação, pega o nome
      if (res.data.length > 0) {
        setAlunoNome(res.data[0].alunoNome)
      }
      return res
    })
    .catch(err => {
      setHistorico([])
      return { data: [] }
    })
  }, [alunoPin, pinValidated])

  // dispara a busca sempre que muda o PIN validado ou o próprio PIN
  useEffect(() => {
    fetchHistory()
  }, [fetchHistory])

  // sugestões de caixas enquanto digita
  const suggestions = codigo
    ? allCaixas
        .filter(c =>
          c.nome.toLowerCase().includes(codigo.toLowerCase()) ||
          c.codigo_barras.includes(codigo)
        )
        .slice(0, 5)
    : []

  const addCaixa = c => {
    setCaixas(prev => [...prev, c])
    toast.success(`Caixa adicionada: ${c.nome}`, { autoClose: 5000 })
    setCodigo('')
  }

  const buscarCaixa = () => {
    const encontrada = allCaixas.find(c => c.codigo_barras === codigo)
    if (!encontrada) {
      toast.error('Caixa não encontrada pelo código.', { autoClose: 5000 })
      return
    }
    addCaixa(encontrada)
  }

  // valida PIN, dispara fetchHistory() e só então toast com o nome
  const validarPin = () => {
    if (alunoPin.trim().length !== 4) {
      toast.warn('PIN deve ter 4 dígitos.', { autoClose: 5000 })
      return
    }
    setPinValidated(true)
    // só exibe o toast após virmos o histórico e capturarmos alunoNome
    fetchHistory().then(res => {
      const nome = res.data[0]?.alunoNome
      if (nome) {
        toast.success(`PIN validado para ${nome}!`, { autoClose: 5000 })
      } else {
        toast.error('Nenhuma movimentação encontrada para esse PIN.', { autoClose: 5000 })
      }
    })
  }

  // operação de entrada/saída
  const operar = async tipo => {
    if (!pinValidated) {
      toast.warn('Valide o PIN antes.', { autoClose: 5000 })
      return
    }
    if (caixas.length === 0) {
      toast.warn('Adicione ao menos uma caixa.', { autoClose: 5000 })
      return
    }
    if (tipo === 'saida') {
      const invalid = caixas.filter(c => {
        const hist = historico.filter(m => m.caixa_id === c.id)
        return hist.length === 0 || hist[0].tipo !== 'entrada'
      })
      if (invalid.length) {
        invalid.forEach(c =>
          toast.error(
            `Não é possível dar saída da caixa "${c.nome}" sem entrada.`,
            { autoClose: 5000 }
          )
        )
        return
      }
    }
    try {
      await Promise.all(
        caixas.map(c =>
          axios.post(`/api/movimentacoes/${tipo}`, {
            caixa_id:  c.id,
            aluno_pin: alunoPin
          })
        )
      )
      toast.success(
        `${tipo === 'entrada' ? 'Entrada' : 'Saída'} registrada para ${alunoNome}!`,
        { autoClose: 5000 }
      )
      // limpa o fluxo mantendo-se na mesma tela
      setCaixas([])
      setAlunoPin('')
      setPinValidated(false)
      setHistorico([])
      setSearchTerm('')
      setFilterDate('')
    } catch {
      toast.error(`Erro ao registrar ${tipo}.`, { autoClose: 5000 })
    }
  }

  const removerCaixa = id => {
    setCaixas(prev => {
      const idx = prev.findIndex(c => c.id === id)
      if (idx === -1) return prev
      const next = [...prev]
      next.splice(idx, 1)
      return next
    })
  }

  const handleDeleteHistory = async id => {
    if (!window.confirm('Deseja realmente excluir esta movimentação?')) return
    try {
      await axios.delete(`/api/movimentacoes/${id}`)
      setHistorico(prev => prev.filter(m => m.id !== id))
      toast.success('Movimentação excluída.', { autoClose: 5000 })
    } catch {
      toast.error('Erro ao excluir movimentação.', { autoClose: 5000 })
    }
  }

  const handleEditHistory = async m => {
    const novoTipo = window.prompt('Novo tipo ("entrada" ou "saida"):', m.tipo)
    if (!novoTipo || !['entrada', 'saida'].includes(novoTipo)) {
      toast.error('Tipo inválido.', { autoClose: 5000 })
      return
    }
    try {
      await axios.put(`/api/movimentacoes/${m.id}`, {
        tipo:     novoTipo,
        aluno_id: m.aluno_id
      })
      setHistorico(prev =>
        prev.map(item =>
          item.id === m.id ? { ...item, tipo: novoTipo } : item
        )
      )
      toast.success('Movimentação atualizada.', { autoClose: 5000 })
    } catch {
      toast.error('Erro ao atualizar movimentação.', { autoClose: 5000 })
    }
  }

  // agrupa caixas para mostrar nome+quantidade
  const caixaCounts = caixas.reduce((acc, c) => {
    if (!acc[c.id]) acc[c.id] = { ...c, qty: 1 }
    else acc[c.id].qty++
    return acc
  }, {})
  const uniqueCaixas = Object.values(caixaCounts)

  return (
    <div className="max-w-4xl mx-auto py-10 px-4 space-y-6">
      <h2 className="text-2xl font-bold">Controle de Esterilização</h2>

      {/* busca de caixas */}
      <div className="bg-white rounded-2xl shadow p-6">
        <div className="flex flex-col md:flex-row gap-4">
          <input
            type="text"
            placeholder="Código ou nome da caixa"
            value={codigo}
            onChange={e => setCodigo(e.target.value)}
            onKeyDown={e =>
              e.key === 'Enter' && (e.preventDefault(), buscarCaixa())
            }
            className="w-full border rounded px-3 py-2"
          />
          <button
            onClick={buscarCaixa}
            className="bg-blue-600 hover:bg-blue-700 text-white font-bold px-4 py-2 rounded-full"
          >
            Adicionar
          </button>
        </div>
      </div>

      {/* caixas selecionadas */}
      {uniqueCaixas.length > 0 && (
        <div className="bg-white rounded-2xl shadow p-6">
          <h3 className="text-lg font-medium mb-2">Caixas selecionadas</h3>
          <div className="flex flex-wrap gap-2">
            {uniqueCaixas.map(c => (
              <div
                key={c.id}
                className="flex items-center bg-gray-100 px-3 py-1 rounded-full"
              >
                <span>{c.nome} ({c.qty})</span>
                <button
                  onClick={() => removerCaixa(c.id)}
                  className="ml-2 text-gray-500"
                >
                  ×
                </button>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* PIN e botões */}
      {uniqueCaixas.length > 0 && (
        <div className="bg-white rounded-2xl shadow p-6 space-y-4">
          <div className="flex flex-col md:flex-row gap-4 items-center">
            <input
              type="password"
              placeholder="PIN do aluno"
              value={alunoPin}
              onChange={e =>
                setAlunoPin(e.target.value.replace(/\D/g, '').slice(0, 4))
              }
              className="flex-1 border rounded px-3 py-2"
            />
            <button
              onClick={validarPin}
              className="bg-indigo-600 hover:bg-indigo-700 text-white font-bold px-4 py-2 rounded-full"
            >
              Validar PIN
            </button>
          </div>
          {pinValidated && (
            <div className="flex flex-col md:flex-row gap-4">
              <button
                onClick={() => operar('entrada')}
                className="bg-green-600 hover:bg-green-700 text-white font-bold px-4 py-2 rounded-full"
              >
                Entrada
              </button>
              <button
                onClick={() => operar('saida')}
                className="bg-red-600 hover:bg-red-700 text-white font-bold px-4 py-2 rounded-full"
              >
                Saída
              </button>
            </div>
          )}
        </div>
      )}

      {/* histórico */}
      <div className="bg-white rounded-2xl shadow p-6">
        <h3 className="text-xl font-bold mb-4">Histórico (últimos 30 dias)</h3>

        {/* filtros */}
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-2 mb-4">
          <input
            type="text"
            placeholder="Pesquisar movimentações..."
            value={searchTerm}
            onChange={e => setSearchTerm(e.target.value)}
            className="flex-1 border rounded px-3 py-2"
          />
          <button
            type="button"
            className="p-2 hover:bg-gray-100 rounded-full"
            onClick={() => datePickerRef.current.setOpen(true)}
          >
            <Calendar className="text-gray-600" size={20} />
          </button>
          <DatePicker
            ref={datePickerRef}
            selected={filterDate ? new Date(filterDate) : null}
            onChange={date => setFilterDate(date.toISOString().slice(0, 10))}
            locale="pt-BR"
            dateFormat="dd/MM/yyyy"
            customInput={<></>}
            withPortal
          />
        </div>

        {/* cabeçalho */}
        <div className="hidden md:grid grid-cols-6 gap-4 text-sm font-semibold text-gray-600 border-b pb-2 mb-2">
          <div>Caixa</div>
          <div>Tipo</div>
          <div>Aluno</div>
          <div>Operador</div>
          <div>Data</div>
          <div className="text-right">Ações</div>
        </div>

        {/* lista */}
        {(() => {
          const filt = historico.filter(m => {
            const txt = searchTerm.toLowerCase()
            const matchTxt = [m.caixaNome, m.tipo, m.alunoNome, m.operadorNome]
              .some(f => f.toLowerCase().includes(txt))
            const matchDate =
              !filterDate ||
              new Date(m.criado_em).toISOString().slice(0, 10) === filterDate
            return matchTxt && matchDate
          })
          if (!filt.length) {
            return <p className="text-gray-500">Nenhuma movimentação registrada.</p>
          }
          return (
            <div className="space-y-4">
              {filt.map(m => (
                <div
                  key={m.id}
                  className="grid grid-cols-1 md:grid-cols-6 gap-4 bg-gray-50 rounded-xl p-4 items-center"
                >
                  <div className="font-medium">{m.caixaNome}</div>
                  <div>{m.tipo}</div>
                  <div>{m.alunoNome}</div>
                  <div>{m.operadorNome}</div>
                  <div>{new Date(m.criado_em).toLocaleString()}</div>
                  <div className="flex justify-end gap-2">
                    <button
                      onClick={() => handleEditHistory(m)}
                      className="px-3 py-1 rounded-lg bg-blue-100 text-blue-800 hover:bg-blue-200 text-sm font-semibold transition"
                    >
                      Editar
                    </button>
                    <button
                      onClick={() => handleDeleteHistory(m.id)}
                      className="px-3 py-1 rounded-lg bg-red-100 text-red-700 hover:bg-red-200 text-sm font-semibold transition"
                    >
                      Excluir
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )
        })()}
      </div>
    </div>
  )
}
